steps.prompt:
You are a professional literary editor. Perform a comprehensive audit of the provided narrative text and project context.

Produce a structured JSON report with the following sections:

{
  "inconsistencies": [
    {
      "entity": "Character/object/location name",
      "issue": "Description of inconsistency",
      "severity": "Low" | "Medium" | "High"
    }
  ],
  "pov_compliance": {
    "issues": [],
    "summary": "Overall POV compliance assessment"
  },
  "narrative_threads": {
    "unresolved": [],
    "resolved": [],
    "summary": "Thread completion assessment"
  },
  "tension_analysis": {
    "current_level": 1-10,
    "target_level": 1-10,
    "consistency": "Consistent" | "Too High" | "Too Low" | "Variable",
    "suggestions": []
  },
  "theme_analysis": {
    "present_themes": [],
    "missing_themes": [],
    "suggestions": []
  },
  "character_voices": {
    "consistent": [],
    "inconsistent": [],
    "suggestions": []
  },
  "language_analysis": {
    "tics": [],
    "repetitions": [],
    "suggestions": []
  },
  "narrative_density": {
    "current": "High" | "Medium" | "Low",
    "suggested": "High" | "Medium" | "Low",
    "notes": ""
  },
  "overall_assessment": "2-3 sentence summary of the text's quality",
  "priority_issues": ["List of 1-3 most critical issues to address"]
}

Be thorough and specific. Reference the provided context files in your analysis.
Only return the JSON object, no other text.
